      if (res.success) {
        setCoaching(res.coaching)
        stopCamera()
        loadStats()
        loadQuestions()
        loadProgress()
        loadHistory()
      }
    } catch (err: any) {
      alert(err.message || 'Failed to get AI coaching. Please try again.')
    } finally {
      setSubmitting(false)
